using System;
using System.DirectoryServices;

public class AdAuthenticator
{
    public bool AuthenticateUser(string username, string password)
    {
        try
        {
            // Define the LDAP connection settings
            var ldapConnectionSettings = new System.DirectoryServices.Protocols.LdapConnectionSettings
            {
                ServerName = "your_ad_server_name",
                Port = 389,
                AuthenticationType = System.DirectoryServices.Protocols.AuthenticationTypes.SecureSocketsLayer | System.DirectoryServices.Protocols.AuthenticationTypes.Seal
            };

            // Create an LDAP connection object
            using (var ldapConnection = new System.DirectoryServices.Protocols.LdapConnection(ldapConnectionSettings))
            {
                // Bind to the Active Directory server with a valid username and password
                ldapConnection.Bind(new System.DirectoryServices.Protocols.Bindings.DistinguishedName("CN=YourUsername,CN=Users,DC=your_domain_name"));

                // Construct an LDAP query to find the user
                var searchFilter = $"(sAMAccountName={username})";
                var searchScope = System.DirectoryServices.SearchScope.Subtree;
                var propertiesToReturn = new[] { "distinguishedName", "userPrincipalName" };

                // Perform the LDAP search
                using (var searcher = new System.DirectoryServices.Protocols.SearchRequest("DC=your_domain_name,DC=com", searchFilter, searchScope, propertiesToReturn))
                {
                    ldapConnection.SendSearchRequest(searcher);

                    var results = searcher.Envelope;
                    if (results != null)
                    {
                        // Get the user's distinguished name
                        var dn = results[0].Attributes["distinguishedName"].Value;

                        // Bind to the user with their password
                        ldapConnection.Bind(new System.DirectoryServices.Protocols.Bindings.DistinguishedName(dn), password);

                        return true;
                    }
                }
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error authenticating user: {ex.Message}");
        }

